mapper.select:
SELECT COUNT(*) FROM ( SELECT l.lesson_id AS scope_item_id FROM learning_progress lp INNER JOIN curriculum_nodes cn ON cn.node_id = lp.node_id INNER JOIN lessons l ON l.node_id = cn.node_id WHERE lp.user_id = #{userId} AND lp.lesson_completed = 1 AND cn.is_active = 1 AND l.is_active = 1
AND lp.subject_id = #{subjectId}
AND cn.level_code = #{levelCode}
UNION ALL
SELECT DISTINCT pp.problem_id AS scope_item_id FROM learning_progress lp INNER JOIN curriculum_nodes cn ON cn.node_id = lp.node_id INNER JOIN practice_problems pp ON pp.node_id = cn.node_id AND pp.subject_id = lp.subject_id WHERE lp.user_id = #{userId} AND lp.practice_passed = 1 AND cn.is_active = 1 AND pp.is_active = 1
AND lp.subject_id = #{subjectId}
AND cn.level_code = #{levelCode}
) available_scope_items
